mapper.select:
SELECT thi.*, twi.workplace_nm, twio.msds_nm as hazmat_nm, COUNT(CASE WHEN thid.in_qty IS NOT NULL THEN 1 END) + COUNT(CASE WHEN thid.out_qty IS NOT NULL THEN 1 END) as result_cnt, (SELECT store_qty FROM ( SELECT store_qty, ROW_NUMBER() OVER (PARTITION BY write_year ORDER BY inout_dt DESC) AS rn FROM esg.tb_hazmat_inout_detail WHERE write_year = #{writeYear} AND doc_no = thi.doc_no AND store_qty IS NOT NULL ) lastData WHERE rn = 1) as last_store_qty FROM esg.tb_hazmat_inout thi LEFT JOIN esg.tb_hazmat_inout_detail thid ON thi.write_year = thid.write_year AND thi.doc_no = thid.doc_no AND thi.doc_type = thid.doc_type LEFT JOIN esg.tb_workplace_info twi ON twi.workplace_id = thi.workplace_id LEFT JOIN esg.tb_msds_info twio ON twio.msds_id = thi.hazmat_id WHERE 1 = 1 AND thi.comp_id = #{compId} AND thi.write_year = #{writeYear}
AND thi.doc_no = #{docNo}
GROUP BY thi.write_year, thi.doc_type, thi.doc_no, thi.comp_id, thi.workplace_id, thi.hazmat_id, thi.msds_synonym,thi.cas_no,thi.daily_volume,thi.daily_time,thi.created_at,thi.created_by,thi.updated_at,thi.updated_by, twi.workplace_nm, twio.msds_nm ORDER BY thi.workplace_id, thi.hazmat_id

mapper.update:
UPDATE esg.tb_hazmat_inout
SET
      msds_synonym = #{msdsSynonym},
      cas_no = #{casNo},
      daily_volume = #{dailyVolume},
      daily_time = #{dailyTime},
      use_yn = #{useYn},
      updated_at = now(),
      updated_by = #{updatedBy}
WHERE comp_id = #{compId}
  AND write_year = #{writeYear}
  AND doc_no = #{docNo}
  AND doc_type = #{docType}

UPDATE esg.tb_hazmat_inout_detail
SET
    in_qty = #{inQty},
    out_qty = #{outQty},
    store_qty = #{storeQty},
    remark = #{remark},
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE 1 = 1
  AND write_year = #{writeYear}
  AND doc_no = #{docNo}
  AND doc_type = #{docType}
  AND doc_seq = #{docSeq}

